<?php
namespace App\Http\Resources;use Illuminate\Http\Request;use Illuminate\Http\Resources\Json\JsonResource;class OrderResource extends JsonResource{public function toArray(Request $request): array{return ['id'=>$this->id,'user_id'=>$this->user_id,'status'=>$this->status,'total_amount'=>(float)$this->total_amount,'delivery_address'=>$this->delivery_address,'cod_amount'=>(float)$this->cod_amount,'payment_status'=>$this->payment_status,'delivery_status'=>$this->delivery_status,'items'=>OrderItemResource::collection($this->whenLoaded('items')),'user'=>new UserResource($this->whenLoaded('user')),'delivery'=>new DeliveryResource($this->whenLoaded('delivery')),'created_at'=>$this->created_at?->toIso8601String(),'updated_at'=>$this->updated_at?->toIso8601String(),];}}